<?php namespace App\Providers; use Illuminate\Support\ServiceProvider; use Illuminate\Support\Facades\Broadcast; class WebsocketServiceProvider extends ServiceProvider { public function register(): void { $this->app->singleton('websocket.manager', function ($app) { return new \App\Services\NotificationService($app['config']); }); } public function boot(): void { Broadcast::routes(['middleware' => ['api', 'auth:sanctum']]); require base_path('routes/channels.php'); } }